-- ============================================================
--  MangroveSense — Iskandar Puteri Blue Carbon Plots
--  MySQL/MariaDB schema + initial data import (v3)
--  Compatible with XAMPP (MySQL 5.7+ / MariaDB 10.3+)
--
--  v3: rebuilt from the latest trees.csv export — lat/lng
--  columns confirmed in correct order (lat ~1.3-1.5, lng ~103.6).
-- ============================================================

DROP DATABASE IF EXISTS mangrove_sense;

CREATE DATABASE mangrove_sense
  CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE mangrove_sense;

-- ── Species lookup ──────────────────────────────────────────
CREATE TABLE species (
  species_id   VARCHAR(100) PRIMARY KEY,
  common_name  VARCHAR(255),
  created_at   TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB;


-- ── Trees ────────────────────────────────────────────────────
CREATE TABLE trees (
  id                     INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  tree_code              VARCHAR(50)  NOT NULL UNIQUE,
  species_id             VARCHAR(100),

  -- Measurements
  trunk_circumference_cm DECIMAL(10,4),
  tree_height_m          DECIMAL(10,4),
  dbh_cm                 DECIMAL(10,4),

  -- Survey coordinates (Malaysian projected CRS from original dataset)
  pos_x                  DECIMAL(16,6) COMMENT 'Easting – Malaysian projected CRS (NOT WGS84)',
  pos_y                  DECIMAL(16,6) COMMENT 'Northing – Malaysian projected CRS (NOT WGS84)',

  -- GPS coordinates (WGS84) — populated for ALL rows as of v3
  lat                    DECIMAL(10,7) COMMENT 'WGS84 latitude',
  lng                    DECIMAL(10,7) COMMENT 'WGS84 longitude',

  -- Form-only fields
  zone_label             VARCHAR(255),
  health_status          ENUM('Healthy','Monitor','Critical') DEFAULT 'Healthy',
  notes                  TEXT,
  photo_filename         VARCHAR(255),

  data_source            ENUM('import','manual') DEFAULT 'manual',
  created_at             TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at             TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,

  FOREIGN KEY (species_id) REFERENCES species(species_id) ON UPDATE CASCADE,
  INDEX idx_species  (species_id),
  INDEX idx_zone     (zone_label),
  INDEX idx_health   (health_status),
  INDEX idx_updated  (updated_at)
) ENGINE=InnoDB;

-- ── Import: 479 rows from trees.csv (WGS84 lat/lng confirmed correct) ──
-- All imported rows have data_source = 'import'.
-- pos_x / pos_y remain in the original Malaysian projected CRS.










